func blockSidebarLabel(n ContentTreeChildNode) string {
	if n.DatatypeLabel != "" {
		return n.DatatypeLabel
	}
	if n.DisplayName != "" {
		return n.DisplayName
	}
	return "Untitled"
}

func blockIndent(depth int) string {
	if depth == 0 {
		return ""
	}
	return "margin-left: " + intToStr(depth*12) + "px"
}

func blockIndentLeaf(depth int) string {
	return "padding-left: " + intToStr(depth*12+20) + "px"
}

func blockIndentLeafWithBg(depth int) string {
	return "padding-left: " + intToStr(depth*12+20) + "px; " + depthBgStyle(depth)
}

func dirtyMarker(isDirty bool) string {
	if isDirty {
		return " *"
	}
	return ""
}

// depthBgStyle returns a subtle background tint that shifts with nesting level.
// Depth 0: transparent, depth 1: rgba(255,255,255,0.02), depth 2: 0.04, etc.
func depthBgStyle(depth int) string {
	if depth == 0 {
		return ""
	}
	// Each level adds 2% white opacity
	pct := depth * 2
	if pct > 10 {
		pct = 10
	}
	return "background-color: rgba(255,255,255,0.0" + intToStr(pct) + ")"
}

